data.content:
MSTest **does not** have `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. Here's what you actually use for boundary checks:

## MSTest Comparison Options

**`Assert.IsTrue` with comparison expressions** (include a message for clear failures):

```csharp
Assert.IsTrue(result >= 0, $"Expected >= 0, but was {result}");
Assert.IsTrue(result <= 100, $"Expected <= 100, but was {result}");
```

**`Assert.AreEqual`** for exact values (with optional delta for doubles):

```csharp
Assert.AreEqual(75.0, result, 0.001);
```

**`Assert.ThrowsException<T>`** for boundary violations:

```csharp
Assert.ThrowsException<ArgumentOutOfRangeException>(() => calc.CalculatePercentage(-1, 10));
```

## Example Tests for Your Code

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    public void CalculatePercentage_ReturnsCorrectValue()
    {
        Assert.AreEqual(75.0, _calc.CalculatePercentage(3, 4), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        Assert.AreEqual(100.0, _calc.CalculatePercentage(10, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_ReturnsZero()
    {
        Assert.AreEqual(0.0, _calc.CalculatePercentage(0, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_ReturnsBoundaryGrades(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    [TestMethod]
    public void NormalizeScore_CapsAt100()
    {
        double result = _calc.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_ResultIsInExpectedRange()
    {
        double result = _calc.NormalizeScore(50, 200);
        Assert.IsTrue(result >= 0 && result <= 100,
            $"Expected result in [0, 100], but was {result}");
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }
}
```

**TL;DR:** Use `Assert.AreEqual(expected, actual, delta)` for numeric comparisons, `Assert.IsTrue(expr, message)` for range checks, and `Assert.ThrowsException<T>` for boundary violations. If you want fluent syntax like `.Should().BeInRange()`, add the **FluentAssertions** NuGet package.
